+import {Options, RuleType} from '../rules';
+import RuleBuilder, {BooleanOptionBuilder, DropdownOptionBuilder, ExampleBuilder, NumberOptionBuilder, OptionBuilderBase, TextAreaOptionBuilder, TextOptionBuilder} from './rule-builder';
+import dedent from 'ts-dedent';
+
+type ListStyle = 'bullet' | 'number';
+type OrderedListStyle = 'always-one' | 'increment';
+
+class AutoTocOptions implements Options {
+  listStyle: ListStyle = 'bullet';
+  bulletMarker: string = '-';
+  orderedListStyle: OrderedListStyle = 'always-one';
+  indentSize: number = 2;
+  minLevel: number = 2;
+  maxLevel: number = 6;
+  title: string = '';
+  useExplicitIds: boolean = false;
+  stripFormattingInToc: boolean = false;
+  excludeHeadings: string[] = [];
+}
+
+type Heading = {level: number, text: string, anchor: string};
+
+const tocStart = /^\\s*<!--\\s*toc\\s*-->\\s*$/i;
+const tocEnd = /^\\s*<!--\\s*\\/toc\\s*-->\\s*$/i;
+const headingLine = /^ {0,3}(#{1,6})[ \	]+(.*?)[ \	]*$/;
+
+function displayText(text: string): string {
+  return text
+      .replace(/!\\[\\[[^\\]]*\\]\\]/g, '')
+      .replace(/!\\[[^\\]]*\\]\\([^)]*\\)/g, '')
+      .replace(/\\[\\[([^\\]|]+)(?:\\|([^\\]]+))?\\]\\]/g, (_match, target, label) => label ?? target)
+      .replace(/\\[([^\\]]*)\\]\\([^)]*\\)/g, '$1');
+}
+
+function stripFormatting(text: string): string {
+  return displayText(text)
+      .replace(/<[^>]*>/g, '')
+      .replace(/(\\*\\*|__|\\*|_|~~|`)/g, '')
+      .replace(/\\\\([\\\\`*{}\\[\\]()#+.!_-])/g, '$1');
+}
+
+function headingAnchor(text: string, useExplicitIds: boolean): string {
+  const explicitId = useExplicitIds ? text.match(/\\s*\\{#([^}\\s]+)\\}\\s*$/) : null;
+  const base = explicitId ? explicitId[1] : stripFormatting(text).replace(/[ \	]+#+\\s*$/, '');
+  return base.toLowerCase().replace(/\\s+/g, '-').replace(/[^a-z0-9-_]/g, '').replace(/-+/g, '-').replace(/^-+|-+$/g, '');
+}
+
+function isExcluded(text: string, exclusions: string[]): boolean {
+  const value = stripFormatting(text).replace(/[ \	]+#+\\s*$/, '').trim();
+  return exclusions.some((exclude) => {
+    if (exclude.startsWith('/') && exclude.endsWith('/') && exclude.length > 2) {
+      try {
+        return new RegExp(exclude.slice(1, -1), 'i').test(value);
+      } catch (_) {
+        // An invalid regex is treated as a literal, which is safer than failing the rule.
+      }
+    }
+    return exclude.toLowerCase() === value.toLowerCase();
+  });
+}
+
+function findHeadings(lines: string[], tocStartLine: number, tocEndLine: number, options: AutoTocOptions): Heading[] {
+  const headings: Heading[] = [];
+  const anchorCounts = new Map<string, number>();
+  let inYaml = lines[0] === '---';
+  let inFence = false;
+  let fence: string = '';
+  let inMath = false;
+
+  for (let index = 0; index < lines.length; index++) {
+    const line = lines[index];
+    if (inYaml) {
+      if (index > 0 && line === '---') inYaml = false;
+      continue;
+    }
+    const fenceMatch = line.match(/^\\s*(`{3,}|~{3,})/);
+    if (fenceMatch) {
+      if (!inFence) {
+        inFence = true;
+        fence = fenceMatch[1][0];
+      } else if (fenceMatch[1][0] === fence) {
+        inFence = false;
+      }
+      continue;
+    }
+    if (inFence) continue;
+    if (/^\\s*\\$\\$\\s*$/.test(line)) {
+      inMath = !inMath;
+      continue;
+    }
+    if (inMath || (index >= tocStartLine && index <= tocEndLine)) continue;
+
+    const match = line.match(headingLine);
+    if (!match) continue;
+    const level = match[1].length;
+    const text = match[2].replace(/[ \	]+#+\\s*$/, '');
+    if (level < options.minLevel || level > options.maxLevel || isExcluded(text, options.excludeHeadings)) continue;
+
+    const baseAnchor = headingAnchor(text, options.useExplicitIds);
+    const count = anchorCounts.get(baseAnchor) ?? 0;
+    anchorCounts.set(baseAnchor, count + 1);
+    headings.push({level, text, anchor: count === 0 ? baseAnchor : `${baseAnchor}-${count}`});
+  }
+  return headings;
+}
+
+function buildToc(headings: Heading[], options: AutoTocOptions): string[] {
+  const tocLines: string[] = [];
+  if (options.title) tocLines.push(options.title);
+  if (options.title && headings.length) tocLines.push('');
+  headings.forEach((heading, index) => {
+    const indent = ' '.repeat(Math.max(0, heading.level - options.minLevel) * options.indentSize);
+    const marker = options.listStyle === 'number' ? (options.orderedListStyle === 'increment' ? `${index + 1}.` : '1.') : options.bulletMarker;
+    const label = options.stripFormattingInToc ? stripFormatting(heading.text) : displayText(heading.text);
+    tocLines.push(`${indent}${marker} [${label}](#${heading.anchor})`);
+  });
+  return tocLines;
+}
+
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.CONTENT,
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const lines = text.split('\
');
+    const startLine = lines.findIndex((line) => tocStart.test(line));
+    if (startLine === -1) return text;
+    const foundEndLine = lines.findIndex((line, index) => index > startLine && tocEnd.test(line));
+    const endLine = foundEndLine === -1 ? startLine : foundEndLine;
+    const headings = findHeadings(lines, startLine, endLine, options);
+    const content = buildToc(headings, options);
+    const replacement = [lines[startLine], '', ...content, '', '<!-- /toc -->', ''];
+    const after = foundEndLine === -1 ? lines.slice(startLine + 1) : lines.slice(foundEndLine + 1);
+    while (after[0] === '') after.shift();
+    return [...lines.slice(0, startLine), ...replacement, ...after].join('\
');
+  }
+
+  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
+    return [new ExampleBuilder({
+      description: 'Generates a table of contents between TOC markers.',
+      before: dedent`
+        <!-- toc -->
+        <!-- /toc -->
+
+        # Title
+        ## First section
+        ### Child section
+      `,
+      after: dedent`
+        <!-- toc -->
+
+        - [First section](#first-section)
+          - [Child section](#child-section)
+
+        <!-- /toc -->
+
+        # Title
+        ## First section
+        ### Child section
+      `,
+    })];
+  }
+
+  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
+    return [
+      new DropdownOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.list-style.name', descriptionKey: 'rules.auto-toc.list-style.description', optionsKey: 'listStyle', records: [{value: 'bullet', description: 'Use bullet list items.'}, {value: 'number', description: 'Use numbered list items.'}]}),
+      new TextOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.bullet-marker.name', descriptionKey: 'rules.auto-toc.bullet-marker.description', optionsKey: 'bulletMarker'}),
+      new DropdownOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.ordered-list-style.name', descriptionKey: 'rules.auto-toc.ordered-list-style.description', optionsKey: 'orderedListStyle', records: [{value: 'always-one', description: 'Use 1. for every item.'}, {value: 'increment', description: 'Increment item numbers.'}]}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.indent-size.name', descriptionKey: 'rules.auto-toc.indent-size.description', optionsKey: 'indentSize'}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.min-level.name', descriptionKey: 'rules.auto-toc.min-level.description', optionsKey: 'minLevel'}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.max-level.name', descriptionKey: 'rules.auto-toc.max-level.description', optionsKey: 'maxLevel'}),
+      new TextOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.title.name', descriptionKey: 'rules.auto-toc.title.description', optionsKey: 'title'}),
+      new BooleanOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.use-explicit-ids.name', descriptionKey: 'rules.auto-toc.use-explicit-ids.description', optionsKey: 'useExplicitIds'}),
+      new BooleanOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.strip-formatting-in-toc.name', descriptionKey: 'rules.auto-toc.strip-formatting-in-toc.description', optionsKey: 'stripFormattingInToc'}),
+      new TextAreaOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.exclude-headings.name', descriptionKey: 'rules.auto-toc.exclude-headings.description', optionsKey: 'excludeHeadings'}),
+    ];
+  }
+}
